  assert forall r | 0 <= r < n :: forall c | 0 <= c < |grid[r]| :: grid[r][c] == '*' ==> (top <= r < bottom && left <= c < right);


















  // === PROVE TIGHTBOUNDS ===
  assert exists c | left <= c < right :: grid[top][c] == '*';
  assert exists c | 0 <= c < |grid[bot]| :: grid[bot][c] == '*';
  assert exists r | 0 <= r < n :: grid[r][left] == '*';
  assert exists r | 0 <= r < n :: grid[r][ri] == '*';

  assert exists c | left <= c < right :: grid[bot][c] == '*';



  assert exists r | top <= r < bottom :: grid[r][right-1] == '*';



  assert exists r | top <= r < bottom :: grid[r][left] == '*' by {
    var r0 :| 0 <= r0 < n && grid[r0][left] == '*';
